import React, { useState, useRef } from 'react'
import { useStaticQuery, graphql } from 'gatsby'
import Typewriter from 'typewriter-effect'

import { menu, numbers } from 'constant'

import { Icon, ScrollTo } from 'components/ui'
import {
  Section,
  WrapHero,
  DonateLink,
  ContainerHero,
  Info,
  InfoSubTitle,
  InfoTitle,
  InfoText,
  InfoTextItem,
  InfoButtonsWrap,
  InfoLink,
  CompositionMobile,
  MobileImg,
  MobileImgWrap,
  Composition,
  WrapperImage,
  StyledImg,
} from './Style'

const Hero = () => {
  const [show, setShow] = useState(false)
  const timeoutRef = useRef(null)

  function resetTimeout() {
    if (timeoutRef.current) {
      clearTimeout(timeoutRef.current)
    }
  }

  React.useEffect(() => {
    resetTimeout()
    // @ts-ignore
    timeoutRef.current = setTimeout(() => setShow(!show), numbers.CHANGE_IMAGE_DELAY)

    return () => {
      resetTimeout()
    }
  }, [show])

  const data = useStaticQuery(graphql`
    query {
      first: file(relativePath: { eq: "images/banner/main-roman.webp" }) {
        childImageSharp {
          fluid(maxWidth: 374, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
      firstMobile: file(relativePath: { eq: "images/hero/main-roman.webp" }) {
        childImageSharp {
          fluid(maxWidth: 374, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
      second: file(relativePath: { eq: "images/banner/main-alex.webp" }) {
        childImageSharp {
          fluid(maxWidth: 374, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
      secondMobile: file(relativePath: { eq: "images/hero/main-alex.webp" }) {
        childImageSharp {
          fluid(maxWidth: 374, quality: 100) {
            ...GatsbyImageSharpFluid_withWebp
          }
        }
      }
    }
  `)

  return (
    <Section id='hero'>
      <WrapHero>
        <ContainerHero>
          <Info>
            <InfoTitle>Defend the right to privacy in Web3</InfoTitle>
            <InfoSubTitle>
              #
              <span translate='no' className='notranslate'>
                <Typewriter
                  options={{
                    strings: [
                      'OpenSourceNotACrime',
                      'PrivacyNotACrime',
                      'DefendAlex',
                      'DefendRomanStorm',
                      'FreeDEVs',
                      'FreeInternet',
                    ],
                    autoStart: true,
                    loop: true,
                    delay: 'natural',
                  }}
                />
              </span>
            </InfoSubTitle>
            <InfoText>
              <InfoTextItem>
                URGENT UPDATE: On&nbsp;August&nbsp;23, 2023, Roman Storm&nbsp;&mdash; the US-based co-founder
                of&nbsp;Tornado Cash&nbsp;&mdash; was arrested despite his ongoing cooperation with the
                US&nbsp;Department of&nbsp;Justice.
              </InfoTextItem>
              <InfoTextItem>
                This arrest happened almost exactly 1&nbsp;year after the arrest of&nbsp;Alex Pertsev&nbsp;&mdash;
                another Tornado Cash co-founder&nbsp;&mdash; by&nbsp;the Dutch authorities, following the August&nbsp;8,
                2022, sanctions imposted against&nbsp;TC by&nbsp;the U.&nbsp;S.&nbsp;Treasury&rsquo;s Office
                of&nbsp;Foreign Assets Control (OFAC).
              </InfoTextItem>
              <InfoTextItem>
                The arrests of Roman Storm and Alex Pertsev are considered a direct attack on the open-source
                development space and may have devastating consequences for developers who write and publish code. This
                is why we need to act NOW to protect our right to code.
                <br />
                <br />
                Thank you for your willingness to contribute to this important cause.
              </InfoTextItem>
            </InfoText>

            <CompositionMobile>
              <MobileImgWrap>
                <MobileImg fluid={data.firstMobile.childImageSharp.fluid} alt='Roman Storm image' />
              </MobileImgWrap>

              <MobileImgWrap isShow={show}>
                <MobileImg fluid={data.secondMobile.childImageSharp.fluid} alt='Alex Pertsev image' />
              </MobileImgWrap>
            </CompositionMobile>

            <Composition>
              <WrapperImage type='first'>
                <StyledImg fluid={data.first.childImageSharp.fluid} alt='Roman Storm image' />
              </WrapperImage>
              <WrapperImage type='second'>
                <StyledImg fluid={data.second.childImageSharp.fluid} alt='Alex Pertsev image' />
              </WrapperImage>
            </Composition>

            <InfoButtonsWrap>
              <DonateLink to={menu.donate}>
                Donate
                <Icon name='arrow' rotate='-90deg' />
              </DonateLink>
              <ScrollTo to={menu.whoIs} href='#learnMore'>
                <InfoLink>Learn more</InfoLink>
              </ScrollTo>
            </InfoButtonsWrap>
          </Info>
        </ContainerHero>
      </WrapHero>
    </Section>
  )
}

export { Hero }
